public class Box {
    int value;
    Box(int v) { this.value = v; }

    static void addFive(Box b) {
        b.value += 5;
    }

    static void addTen(int x) {
        x += 10;
    }

    public static void main(String[] args) {
        Box box = new Box(1);
        addFive(box);
        System.out.println(box.value);

        int n = 1;
        addTen(n);
        System.out.println(n);
    }
}
